 98→const authHeaders = (token?: string): Record<string, string> => {
 99→  if (!token) {
100→    return {};
101→  }
102→
103→  return {
104→    Authorization: `Bearer ${token}`,
105→  };
106→};
107→
108→export const mobileApi = {
109→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
110→    const params = new URLSearchParams();
111→    params.set('limit', String(limit));
112→    if (cursor) {
113→      params.set('before', cursor);
114→    }
115→    if (userId) {
116→      params.set('userId', userId);
117→    }
118→
119→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
120→      method: 'GET',
121→    });
122→  },
123→
124→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
125→    const params = new URLSearchParams();
126→    if (userId) {
127→      params.set('userId', userId);
128→    }
129→
130→    const suffix = params.toString() ? `?${params.toString()}` : '';
131→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
132→      method: 'GET',
133→    });
134→  },
135→
136→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
137→    const params = new URLSearchParams();
138→    params.set('query', query.trim());
139→    params.set('limit', String(limit));
140→
141→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
142→      method: 'GET',
143→    });
144→  },
145→
146→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
147→    const params = new URLSearchParams();
148→    params.set('query', query.trim());
149→    params.set('limit', String(limit));
150→    if (userId) {
151→      params.set('userId', userId);
152→    }
153→
154→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
155→      method: 'GET',
156→    });
157→  },
158→
159→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
160→    const params = new URLSearchParams();
161→    params.set('limit', String(limit));
162→    if (cursor) {
163→      params.set('before', cursor);
164→    }
165→
166→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
167→      method: 'GET',
168→      headers: {
169→        ...authHeaders(token),
170→      },
171→    });
172→  },
173→
174→  async getUserData(userId: string): Promise<UserDataResponse> {
175→    const params = new URLSearchParams();
176→    params.set('userId', userId);
177→
178→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
179→      method: 'GET',
180→    });
181→  },
182→
183→  async getCanvasGallery(
184→    userId?: string,
185→    limit = 36,
186→    sort: 'hottest' | 'newest' = 'hottest',
187→    cursor?: string | null,
188→  ): Promise<CursorPage<JournalItem>> {
189→    const params = new URLSearchParams();
190→    params.set('limit', String(limit));
191→    params.set('sort', sort);
192→    if (userId) {
193→      params.set('userId', userId);
194→    }
195→    if (cursor) {
196→      params.set('cursor', cursor);
197→    }
198→
199→    return apiRequest<CursorPage<JournalItem>>(`/journals/canvas/gallery?${params.toString()}`, {
200→      method: 'GET',
201→    });
202→  },
203→
204→  async getFreedomWallWeeks(limit = 8, token?: string): Promise<{ data?: FreedomWeek[] }> {
205→    const params = new URLSearchParams();
206→    params.set('limit', String(limit));
207→
208→    return apiRequest<{ data?: FreedomWeek[] }>(`/freedom-wall/weeks?${params.toString()}`, {
209→      method: 'GET',
210→      headers: {
211→        ...authHeaders(token),
212→      },
213→    });
214→  },
215→
216→  async getCurrentFreedomWallWeek(token?: string): Promise<{ data?: FreedomWeek }> {
217→    return apiRequest<{ data?: FreedomWeek }>('/freedom-wall/current', {
218→      method: 'GET',
219→      headers: {
220→        ...authHeaders(token),
221→      },
222→    });
223→  },
224→
225→  async getFreedomWallItems(
226→    weekId: string,
227→    options: { limit?: number; cursor?: string; types?: string[] | string } = {},
228→    token?: string,
229→  ): Promise<CursorPage<FreedomItem>> {
230→    const params = new URLSearchParams();
231→    params.set('limit', String(options.limit ?? 200));
232→    if (options.cursor) {
233→      params.set('cursor', options.cursor);
234→    }
235→    if (Array.isArray(options.types) && options.types.length > 0) {
236→      params.set('types', options.types.join(','));
237→    } else if (typeof options.types === 'string' && options.types.trim().length > 0) {
238→      params.set('types', options.types.trim());
239→    }
240→
241→    return apiRequest<CursorPage<FreedomItem>>(
242→      `/freedom-wall/${encodeURIComponent(weekId)}/items?${params.toString()}`,
243→      {
244→        method: 'GET',
245→        headers: {
246→          ...authHeaders(token),
247→        },
248→      },
249→    );
250→  },
251→
252→  async getUniversePosts(
253→    viewport: { minX: number; maxX: number; minY: number; maxY: number },
254→    limit = 200,
255→  ): Promise<{ data?: UniversePost[] }> {
256→    const params = new URLSearchParams();
257→    params.set('minX', String(viewport.minX));
258→    params.set('maxX', String(viewport.maxX));
259→    params.set('minY', String(viewport.minY));
260→    params.set('maxY', String(viewport.maxY));
261→    params.set('limit', String(limit));
262→
263→    return apiRequest<{ data?: UniversePost[] }>(`/universe/posts?${params.toString()}`, {
264→      method: 'GET',
265→    });
266→  },
267→
268→  async getUserByUsername(username: string): Promise<UserDataResponse> {
269→    return apiRequest<UserDataResponse>(
270→      `/user/${encodeURIComponent(username)}`,
271→      {method: 'GET'},
272→    );
273→  },
274→
275→  async getRelatedPosts(journalId: string): Promise<{data: JournalItem[]}> {
276→    return apiRequest<{data: JournalItem[]}>(
277→      `/journal/${encodeURIComponent(journalId)}/related`,
278→      {method: 'GET'},
279→    );
280→  },
281→
282→  async getUserJournals(userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
283→    const params = new URLSearchParams();
284→    params.set('limit', String(limit));
285→    params.set('authorId', userId);
286→    if (cursor) params.set('before', cursor);
287→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {method: 'GET'});
288→  },
289→
290→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
291→    const formData = new FormData();
292→
293→    const lexicalPayload = {
294→      root: {
295→        children: [
296→          {
297→            type: 'paragraph',
298→            children: [
299→              {
300→                type: 'text',
301→                text: payload.plainText,
302→                detail: 0,
303→                format: 0,
304→                mode: 'normal',
305→                style: '',
306→                version: 1,
307→              },
308→            ],
309→            direction: null,
310→            format: '',
311→            indent: 0,
312→            version: 1,
313→          },
314→        ],
315→        direction: null,
316→        format: '',
317→        indent: 0,
318→        type: 'root',
319→        version: 1,
320→      },
321→    };
322→
323→    formData.append('title', payload.title);
324→    formData.append('content', JSON.stringify(lexicalPayload));
325→    formData.append('post_type', 'text');
326→
327→    return apiRequest<{ message?: string }>('/save-journal', {
328→      method: 'POST',
329→      headers: {
330→        ...authHeaders(token),
331→      },
332→      body: formData,
333→      timeoutMs: 30000,
334→      retries: 0,
335→    });
336→  },
337→};
