 28→  const ringColor =
 29→    badge === 'legend'
 30→      ? colors.badgeLegendBorder
 31→      : badge === 'og'
 32→        ? colors.badgeOGBorder
 33→        : 'transparent';
 34→
 35→  const content = uri ? (
 36→    <Image
 37→      source={{uri}}
