125→export function HomeFeedScreen({navigation}: Props) {
126→  const {user, session} = useAuth();
127→  const {colors} = useTheme();
128→  const token = session?.access_token ?? '';
129→  const [refreshing, setRefreshing] = useState(false);
130→  const [activeFilter, setActiveFilter] = useState('all');
131→
132→  const feedQuery = useInfiniteQuery({
133→    queryKey: ['feed', user?.id],
134→    queryFn: ({pageParam}) =>
135→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
136→    initialPageParam: null as string | null,
137→    getNextPageParam: lastPage => getNextCursor(lastPage),
138→  });
139→
140→  const reactionMutation = useMutation({
141→    mutationFn: async ({
142→      journalId,
143→      receiverId,
144→      reactionType,
145→    }: {
146→      journalId: string;
147→      receiverId: string;
148→      reactionType: string;
149→    }) => {
150→      if (!token) throw new Error('Please log in to react.');
151→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
152→    },
153→    onMutate: async ({journalId, reactionType}) => {
154→      await queryClient.cancelQueries({queryKey: ['feed']});
155→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
156→        ['feed', user?.id],
157→      );
158→      if (prev) {
159→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
160→          ['feed', user?.id],
161→          old => {
162→            if (!old) return old;
163→            return {
164→              ...old,
165→              pages: old.pages.map(page => ({
166→                ...page,
167→                data: page.data.map(item => {
168→                  if (item.id !== journalId) return item;
169→                  const removing = item.user_reaction === reactionType;
170→                  const currentCount =
171→                    (item.reaction_count?.[0]?.count ??
172→                      item.like_count?.[0]?.count ??
173→                      item.likes_count ??
174→                      0) as number;
175→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
176→                  return {
177→                    ...item,
178→                    user_reaction: removing ? null : reactionType,
179→                    has_liked: removing ? false : true,
180→                    like_count: [{count: Math.max(0, currentCount + delta)}],
181→                  };
182→                }),
183→              })),
184→            };
185→          },
186→        );
187→      }
188→      return {prev};
189→    },
190→    onError: (_err, _vars, context) => {
191→      if (context?.prev) {
192→        queryClient.setQueryData(['feed', user?.id], context.prev);
193→      }
194→    },
195→    onSettled: () => {
196→      queryClient.invalidateQueries({queryKey: ['feed']});
197→    },
198→  });
199→
200→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
201→    if (!token) return;
202→    reactionMutation.mutate({journalId, receiverId, reactionType});
203→  };
204→
205→  const posts = useMemo(
206→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
207→    [feedQuery.data?.pages],
208→  );
209→
210→  const onRefresh = async () => {
211→    setRefreshing(true);
212→    try {
213→      await feedQuery.refetch();
214→    } finally {
215→      setRefreshing(false);
216→    }
217→  };
218→
219→  const handleQuickAction = (key: string) => {
220→    if (key === 'canvas') {
221→      navigation.navigate('Canvas');
222→    } else if (key === 'freedom_wall') {
223→      navigation.navigate('FreedomWall');
224→    } else if (key === 'universe') {
225→      navigation.navigate('Universe');
226→    } else {
227→      setActiveFilter(key);
228→    }
229→  };
230→
231→  return (
232→    <SafeAreaView
233→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
234→      edges={['top']}>
235→      {/* Branded header */}
236→      <View
237→        style={[
238→          styles.header,
239→          {borderBottomColor: colors.borderCard},
240→        ]}>
241→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
242→          iskrib
243→        </Text>
244→      </View>
245→
246→      {/* Filter chips */}
247→      <View style={styles.chipRow}>
248→        <ScrollView
249→          horizontal
250→          showsHorizontalScrollIndicator={false}
251→          contentContainerStyle={styles.chipScroll}>
252→          {QUICK_ACTIONS.map(action => (
253→            <Chip
254→              key={action.key}
255→              label={action.label}
256→              active={activeFilter === action.key}
257→              onPress={() => handleQuickAction(action.key)}
258→            />
259→          ))}
260→        </ScrollView>
261→      </View>
262→
263→      {/* Feed */}
264→      <FlatList
265→        data={posts}
266→        onRefresh={onRefresh}
267→        refreshing={refreshing}
268→        onEndReachedThreshold={0.25}
269→        onEndReached={() => {
270→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
271→            feedQuery.fetchNextPage();
272→          }
273→        }}
274→        contentContainerStyle={styles.listContent}
275→        showsVerticalScrollIndicator={false}
276→        ListEmptyComponent={
277→          feedQuery.isLoading ? (
278→            <View style={styles.skeletonList}>
279→              <PostCardSkeleton />
280→              <PostCardSkeleton />
281→              <PostCardSkeleton />
282→            </View>
283→          ) : (
284→            <EmptyState
285→              title="No posts yet"
286→              subtitle="Pull to refresh or create your first journal post."
287→            />
288→          )
289→        }
290→        ListFooterComponent={
291→          feedQuery.isFetchingNextPage ? (
292→            <View style={styles.loadingMore}>
293→              <PostCardSkeleton />
294→            </View>
295→          ) : null
296→        }
297→        keyExtractor={item => item.id}
298→        renderItem={({item}) => {
299→          const preview = extractPlainText(item.content).slice(0, 180);
300→          const likeCount = resolveCount(
301→            item.like_count,
302→            item.likes_count,
303→          );
304→          const commentCount = resolveCount(
305→            item.comment_count,
306→            item.comments_count,
307→          );
308→          const bookmarkCount = resolveCount(item.bookmark_count);
309→          const bannerImage = extractBannerImage(
310→            item.content,
311→            (item as any).images,
