 29→export function StoryDashboardScreen({navigation}: Props) {
 30→  const {colors} = useTheme();
 31→  const {session} = useAuth();
 32→  const token = session?.access_token ?? '';
 33→  const queryClient = useQueryClient();
 34→
 35→  const myStoriesQuery = useInfiniteQuery({
 36→    queryKey: ['stories-dashboard', token],
 37→    enabled: token.length > 0,
 38→    queryFn: ({pageParam}) => storyApi.getMyStories(token, {limit: 10, before: pageParam ?? null}),
 39→    initialPageParam: null as string | null,
 40→    getNextPageParam: page => getNext(page),
 41→  });
 42→
 43→  const deleteMutation = useMutation({
 44→    mutationFn: (storyId: string) => storyApi.deleteStory(token, storyId),
 45→    onSuccess: () => {
 46→      queryClient.invalidateQueries({queryKey: ['stories-dashboard', token]});
 47→      queryClient.invalidateQueries({queryKey: ['stories-browser']});
 48→    },
 49→  });
 50→
 51→  const stories = useMemo(
 52→    () => myStoriesQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
 53→    [myStoriesQuery.data?.pages],
 54→  );
 55→
 56→  const onDelete = (storyId: string, title: string) => {
 57→    Alert.alert('Delete story', `Delete "${title}"?`, [
 58→      {text: 'Cancel', style: 'cancel'},
 59→      {text: 'Delete', style: 'destructive', onPress: () => deleteMutation.mutate(storyId)},
 60→    ]);
 61→  };
 62→
 63→  return (
 64→    <Screen scroll={false}>
 65→      <View style={styles.header}>
 66→        <Text style={[styles.title, {color: colors.textPrimary}]}>My Stories</Text>
 67→        <PrimaryButton
 68→          label="New Story"
 69→          onPress={() => navigation.navigate('StoryEditor', {})}
 70→        />
 71→      </View>
 72→
 73→      {!token ? (
 74→        <Text style={[styles.meta, {color: colors.textMuted}]}>Login required.</Text>
 75→      ) : myStoriesQuery.isLoading ? (
 76→        <View style={styles.loading}>
 77→          <ActivityIndicator color={colors.accentAmber} />
 78→          <Text style={[styles.meta, {color: colors.textMuted}]}>Loading stories...</Text>
 79→        </View>
